<?php
// pre-built phar with all entries compressed via Phar::GZ. contains:
//   readme.md, lib/util.php, data/payload.json, a/b/c/deep.txt
// built with: php -d phar.readonly=0 (Phar::compressFiles(Phar::GZ))
$pharB64 = '';

$pharFile = sys_get_temp_dir() . '/zphp_phar_gz_compat_' . mt_rand(1000000, 9999999) . '.phar';
file_put_contents($pharFile, base64_decode($pharB64));

echo file_get_contents("phar://$pharFile/readme.md");
echo file_get_contents("phar://$pharFile/lib/util.php");
echo file_get_contents("phar://$pharFile/data/payload.json") . "\n";
echo file_get_contents("phar://$pharFile/a/b/c/deep.txt");

echo "exists readme: " . (file_exists("phar://$pharFile/readme.md") ? "y" : "n") . "\n";
echo "is_file deep: " . (is_file("phar://$pharFile/a/b/c/deep.txt") ? "y" : "n") . "\n";
echo "is_dir lib: " . (is_dir("phar://$pharFile/lib") ? "y" : "n") . "\n";

$f = fopen("phar://$pharFile/data/payload.json", 'r');
echo "fread1: " . fread($f, 5) . "\n";
echo "fread2: " . fread($f, 100);
echo "\nfeof: " . (feof($f) ? "y" : "n") . "\n";
rewind($f);
echo "rewind: " . fread($f, 100);
echo "\n";
fclose($f);

echo "md5 readme: " . md5(file_get_contents("phar://$pharFile/readme.md")) . "\n";
echo "md5 util: " . md5(file_get_contents("phar://$pharFile/lib/util.php")) . "\n";
echo "md5 json: " . md5(file_get_contents("phar://$pharFile/data/payload.json")) . "\n";

@unlink($pharFile);
